    def _cx_fields(
        seg: HL7Segment, field_n: int, prefix: str, *, repeating: bool = True
    ) -> dict:
        """CX (Extended Composite ID with Check Digit) — 12 components + HD sub-components."""
        def gc(comp):
            if repeating:
                return _v(seg.get_rep_component(field_n, 1, comp))
